PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "cities" (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `name` text, `country_id` integer NULL, `state_id` integer NULL, `parent_city_id` integer NULL, `type` varchar(50) DEFAULT 'city', latitude REAL, longitude REAL, FOREIGN KEY (`parent_city_id`) REFERENCES `cities` (`id`) ON DELETE CASCADE);
COMMIT;
